      "keystrokes": "xlsx write sheet Task range C11:L20 formula '=INDEX(Data!$B$11:$K$20,MATCH(Task!A11,Data!$A$11:$A$20,0),MATCH(Task!$B$10,Data!$B$10:$K$10,0))'\n",
